mapper.update:
UPDATE event.popups
SET  title       = #{title}
    ,content     = #{content}
    ,status      = #{status}
    ,sort_seq    = #{sortSeq}
    ,start_at    = #{startAt}
    ,end_at      = #{endAt}
    ,updated_by  = #{updatedBy}
    ,updated_at  = NOW()
WHERE popup_seq  = #{popupSeq}
  AND deleted_at IS NULL

UPDATE event.popups
SET  deleted_at = NOW()
    ,updated_by = #{userSeq}
    ,updated_at = NOW()
WHERE popup_seq  = #{popupSeq}
  AND deleted_at IS NULL
